@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    We value your privacy. This page describes how we handle your personal data
    and use cookies to improve your experience.
</p>

<h2>Cookie Consent</h2>

@if (HasConsented)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy. Thank you!
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

<h2>What We Collect</h2>
<ul>
    <li>Essential cookies required for the site to function.</li>
    <li>Analytics cookies to help us improve (only with your consent).</li>
</ul>

<h2>Your Rights</h2>
<p>
    You may withdraw consent at any time by clearing your browser cookies
    or contacting us directly.
</p>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsented =>
        HttpContext?.Request.Cookies.ContainsKey("consent") == true;
}

